class Solution:
    def handleProjection(self, query: dict) -> dict:
        projection = {}
        for field in query:
            if query[field] is None:
                continue
            elif isinstance(query[field], dict):
                for nestedField in query[field]:
                    if query[field][nestedField] is not None:
                        projection[field + '.' + nestedField] = 1
            else:
                projection[field] = 1
        return {'query': {'projection': projection}}
